#include <bits/stdc++.h>
using namespace std;
const int N=20005;
int tim,dfn[N],low[N],cnt,n,m,a[N],vis[N];
vector<int> G[N];
void tarjan(int u,int fa)
{
	dfn[u]=low[u]=++tim;
    int cnt=0;
	for(int i=0;i<G[u].size();i++)
    {
		int v=G[u][i];
		if(dfn[v]==0)
        {
            cnt++;
			tarjan(v,u);
			low[u]=min(low[u],low[v]);
            if(low[v]>=dfn[u])
            {
                vis[u]=1;
            }
		}
		else if(dfn[v]<dfn[u]&&v!=fa)
        {
            low[u]=min(low[u],dfn[v]);
        }
	}
    if(fa==-1&&cnt==1)
    {
        vis[u]=0;
    }
}
int main()
{
    cin>>n>>m;
    for(int i=1;i<=m;i++)
    {
        int u,v;
        cin>>u>>v;
        G[u].push_back(v);
        G[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
    {
        if(dfn[i]==0) tarjan(i,-1);
    }
    int cnt=0;
    for(int i=1;i<=n;i++)
    {
        if(vis[i]==1) cnt++;
    }
    cout<<cnt<<'\n';
    for(int i=1;i<=n;i++)
    {
        if(vis[i]==1) cout<<i<<" ";
    }
    return 0;
}
